{"content": "     1|#!/usr/bin/env node
     2|/**
     3| * @bin gsd
     4| * @description GSD CLI wrapper — dispatches to the correct command module.
     5| *
     6| * Usage:
     7| *   gsd status [project]
     8| *   gsd discuss <project> [--goal 'description']
     9| *   gsd plan <project> [--phase 01-name]
    10| *   gsd execute <project> [--wave N] [--dry-run]
    11| *   gsd verify <project>
    12| */
    13|
    14|import { fileURLToPath } from 'node:url';
    15|import { dirname, join } from 'node:path';
    16|
    17|const __dirname = dirname(fileURLToPath(import.meta.url));
    18|const commandsDir = join(__dirname, '..', 'src', 'commands');
    19|
    20|const COMMANDS = {
    21|  status:  'gsd-status.js',
    22|  discuss: 'gsd-discuss.js',
    23|  plan:    'gsd-plan.js',
    24|  execute: 'gsd-execute.js',
    25|  verify:  'gsd-verify.js',
    26|};
    27|
    28|const ALIASES = {
    29|  s: 'status',
    30|  d: 'discuss',
    31|  p: 'plan',
    32|  e: 'execute',
    33|  x: 'execute',
    34|  v: 'verify',
    35|};
    36|
    37|function printUsage() {
    38|  console.log(`
    39|  GSD — Get Shit Done
    40|
    41|  Usage: gsd <command> [args]
    42|
    43|  Commands:
    44|    status  [project]                       Show project status
    45|    discuss <project> [--goal 'desc']       Initialize or review project discussion
    46|    plan    <project> [--phase 01-name]     Generate phase plan
    47|    execute <project> [--wave N] [--dry-run] Dispatch tasks to agents
    48|    verify  <project>                       Verify completed tasks
    49|
    50|  Aliases: s=status, d=discuss, p=plan, e/x=execute, v=verify
    51|
    52|  Examples:
    53|    gsd status
    54|    gsd s website-seo
    55|    gsd discuss new-project --goal 'Build a client portal'
    56|    gsd plan website-seo --phase 01-metadata-fixes
    57|    gsd execute website-seo --dry-run
    58|    gsd verify website-seo
    59|`);
    60|}
    61|
    62|async function run() {
    63|  const args = process.argv.slice(2);
    64|
    65|  if (args.length === 0 || args[0] === '--help' || args[0] === '-h') {
    66|    printUsage();
    67|    process.exit(args.length === 0 ? 2 : 0);
    68|  }
    69|
    70|  let command = args[0].toLowerCase();
    71|  const commandArgs = args.slice(1);
    72|
    73|  // Resolve aliases
    74|  if (ALIASES[command]) command = ALIASES[command];
    75|
    76|  const commandFile = COMMANDS[command];
    77|  if (!commandFile) {
    78|    console.error(`Unknown command: ${args[0]}`);
    79|    console.error(`Available: ${Object.keys(COMMANDS).join(', ')}`);
    80|    process.exit(2);
    81|  }
    82|
    83|  const mod = await import(join(commandsDir, commandFile));
    84|  await mod.main(commandArgs);
    85|}
    86|
    87|run().catch(err => {
    88|  console.error(err.message);
    89|  process.exit(1);
    90|});
    91|", "total_lines": 90, "file_size": 2290, "truncated": false, "is_binary": false, "is_image": false}

