     7|
     8|import { readFile, writeFile } from 'node:fs/promises';
     9|
    10|// ─── Config-Driven MC Settings ──────────────────────────────────────────────────
    11|
    12|/** @type {Object|null} Cached config */
    13|let _mcConfig = null;
    14|
    15|async function getMCConfig() {
    16|  if (_mcConfig) return _mcConfig;
    17|
    18|  // Try loading from .planning/config.json
    19|  for (const p of ['.planning/config.json', '../.planning/config.json']) {
    20|    try {
    21|      const raw = await readFile(p, 'utf-8');
    22|      const config = JSON.parse(raw);
    23|      _mcConfig = config.mission_control || {};
    24|      return _mcConfig;
    25|    } catch { /* try next */ }
    26|  }
    27|
    28|  _mcConfig = {};
    29|  return _mcConfig;
    30|}
    31|
    32|function getMCBase(config) {
    33|  return config?.base_url
    34|    || process.env.MC_BASE_URL
    35|    || 'https://ops.lawyerincorporated.com';
    36|}
    37|
    38|function getMCApiKey(config) {
    39|  return config?.api_key
    40|    || process.env.MC_API_KEY
    41|    || '';
    42|}
    43|
    44|/**
    45| * Build headers for MC API calls.
    46| * @param {Object} mcConfig
    47| * @returns {Object}
    48| */
    49|function getMCHeaders(mcConfig) {
    50|  return {
    51|    'Content-Type': 'application/json',
    52|    'x-api-key': getMCApiKey(mcConfig),
    53|  };
    54|}
    55|
    56|/**
    57| * Map GSD task status strings to MC pipeline stages.
    58| * MC pipeline: inbox → assigned → in_progress → quality_review → done
    59| */
    60|const STATUS_TO_MC = {
    61|  'planned':     'inbox',
    62|  'assigned':    'assigned',
    63|  'dispatched':  'assigned',
    64|  'in_progress': 'in_progress',
    65|  'blocked':     'in_progress',   // MC doesn't have a blocked state; keep in progress
    66|  'reviewing':   'quality_review',
    67|  'verified':    'quality_review',
    68|  'done':        'done',
    69|  'shipped':     'done',
    70|};
    71|
    72|/**
    73| * @typedef {Object} MCTask
    74| * @property {string} id - MC ticket ref (e.g., "GSD-001")
    75| * @property {string} title
    76| * @property {string} description
    77| * @property {string} status
    78| * @property {string} assignee
    79| * @property {string} taskId - Original PLAN.md task ID
    80| */
    81|
    82|/**
    83| * @typedef {Object} TaskMapping
    84| * @property {string} planTaskId - PLAN.md task ID (e.g., "SEO-01")
    85| * @property {string} mcTicketRef - MC ticket ref (e.g., "GSD-005")
    86| * @property {string} mcTaskId - MC internal ID
    87| */
    88|
    89|// ─── In-memory mapping store ───────────────────────────────────────────────────
    90|
    91|/** @type {Map<string, TaskMapping>} planTaskId → mapping */
    92|const _taskMappings = new Map();
    93|
    94|/**
    95| * Get the task ID mapping store. Useful for persistence.
    96| * @returns {Map<string, TaskMapping>}
    97| */
    98|export function getMappings() {
    99|  return _taskMappings;
   100|}
   101|
   102|/**
   103| * Load mappings from a JSON object (e.g., read from disk).
   104| * @param {TaskMapping[]} mappings
   105| */
   106|export function loadMappings(mappings) {
   107|  _taskMappings.clear();
   108|  for (const m of mappings) {
   109|    _taskMappings.set(m.planTaskId, m);
   110|  }
   111|}
   112|
   113|/**
   114| * Export mappings as a serializable array.
   115| * @returns {TaskMapping[]}
   116| */
   117|export function exportMappings() {
   118|  return [..._taskMappings.values()];
   119|}
   120|
   121|/** Default path for persisted mappings */
   122|const DEFAULT_MAPPINGS_PATH = '.planning/mc-mappings.json';
   123|
   124|/**
   125| * Save mappings to disk for persistence across restarts.
   126| * @param {string} [filePath] - Path to save mappings (default: .planning/mc-mappings.json)
   127| * @returns {Promise<void>}
   128| */
   129|export async function saveMappings(filePath = DEFAULT_MAPPINGS_PATH) {
   130|  const data = JSON.stringify(exportMappings(), null, 2);
   131|  await writeFile(filePath, data, 'utf-8');
   132|}
   133|
   134|/**
   135| * Load mappings from disk.
   136| * @param {string} [filePath] - Path to load mappings from
   137| * @returns {Promise<boolean>} true if loaded successfully
   138| */
   139|export async function loadMappingsFromDisk(filePath = DEFAULT_MAPPINGS_PATH) {
   140|  try {
   141|    const raw = await readFile(filePath, 'utf-8');
   142|    const mappings = JSON.parse(raw);
   143|    loadMappings(mappings);
   144|    return true;
   145|  } catch {
   146|    return false;
   147|  }
