   149|
   150|// ─── MC API Helpers ────────────────────────────────────────────────────────────
   151|
   152|/**
   153| * Make an authenticated request to the Mission Control API.
   154| *
   155| * @param {string} path - API path (e.g., "/api/tasks")
   156| * @param {Object} [options] - fetch options override
   157| * @returns {Promise<{ok: boolean, status: number, data: any}>}
   158| */
   159|async function mcFetch(path, options = {}) {
   160|  const mcConfig = await getMCConfig();
   161|  const base = getMCBase(mcConfig);
   162|  const headers = getMCHeaders(mcConfig);
   163|
   164|  if (!getMCApiKey(mcConfig)) {
   165|    return { ok: false, status: 0, data: null, error: 'MC_API_KEY not configured. Set MC_API_KEY env var or add to .planning/config.json.' };
   166|  }
   167|
   168|  const url = `${base}${path}`;
   169|  try {
   170|    const res = await fetch(url, {
   171|      headers,
   172|      ...options,
   173|    });
   174|
   175|    let data;
   176|    const contentType = res.headers.get('content-type') || '';
   177|    if (contentType.includes('application/json')) {
   178|      data = await res.json();
   179|    } else {
   180|      data = await res.text();
   181|    }
   182|
   183|    return { ok: res.ok, status: res.status, data };
   184|  } catch (err) {
   185|    return { ok: false, status: 0, data: null, error: err.message };
   186|  }
   187|}
   188|
   189|// ─── Task CRUD ─────────────────────────────────────────────────────────────────
   190|
   191|/**
   192| * Create a Mission Control task from a parsed PLAN.md task.
   193| *
   194| * @param {import('./parser.js').Task} task - Parsed task from PLAN.md
   195| * @param {Object} [meta] - Optional plan metadata for context
   196| * @param {string} [meta.phase] - Phase name
   197| * @param {string} [meta.projectId] - MC project ID
   198| * @returns {Promise<{success: boolean, ticketRef: string|null, mcId: string|null, error: string|null}>}
   199| */
   200|export async function createMCTask(task, meta = {}) {
   201|  const description = [
   202|    task.description,
   203|    '',
   204|    `Type: ${task.type}`,
   205|    `Wave: ${task.wave}`,
   206|    task.approval ? `Approval required: ${task.approval}` : '',
   207|    `Verification: ${task.verify}`,
   208|    `Done when: ${task.done}`,
   209|    '',
   210|    `Source: PLAN.md task ${task.id}`,
   211|    meta.phase ? `Phase: ${meta.phase}` : '',
   212|  ].filter(Boolean).join('\n');
   213|
   214|  const payload = {
   215|    title: `[${task.id}] ${task.title}`,
   216|    description,
   217|    status: STATUS_TO_MC[task.status || 'planned'] || 'inbox',
   218|    assignee: task.assignee,
   219|    priority: task.approval === 'aaron' ? 'high' : 'medium',
   220|    tags: [task.type, `wave-${task.wave}`, 'gsd-managed'],
   221|  };
   222|
   223|  if (meta.projectId) {
   224|    payload.project_id = meta.projectId;
   225|  }
   226|
   227|  const result = await mcFetch('/api/tasks', {
   228|    method: 'POST',
   229|    body: JSON.stringify(payload),
   230|  });
   231|
   232|  if (result.ok && result.data) {
   233|    const ticketRef = result.data.ticket_ref || result.data.ticketRef || result.data.id;
   234|    const mcId = result.data.id || result.data._id;
   235|
   236|    // Store mapping and persist to disk
   237|    _taskMappings.set(task.id, {
   238|      planTaskId: task.id,
   239|      mcTicketRef: ticketRef,
   240|      mcTaskId: mcId,
   241|    });
   242|    saveMappings().catch(() => {}); // best-effort persist
   243|
   244|    return { success: true, ticketRef, mcId, error: null };
   245|  }
   246|
   247|  return {
   248|    success: false,
   249|    ticketRef: null,
   250|    mcId: null,
   251|    error: result.error || `MC API returned ${result.status}: ${JSON.stringify(result.data)}`,
   252|  };
   253|}
   254|
   255|/**
   256| * Update an existing MC task's status.
   257| *
   258| * @param {string} planTaskId - PLAN.md task ID
   259| * @param {string} newStatus - New GSD status (planned, in_progress, done, etc.)
   260| * @param {Object} [extra] - Additional fields to update
   261| * @returns {Promise<{success: boolean, error: string|null}>}
   262| */
   263|export async function updateMCTaskStatus(planTaskId, newStatus, extra = {}) {
   264|  const mapping = _taskMappings.get(planTaskId);
   265|  if (!mapping) {
   266|    return { success: false, error: `No MC mapping found for task "${planTaskId}"` };
   267|  }
   268|
   269|  const mcStatus = STATUS_TO_MC[newStatus] || newStatus;
   270|
   271|  const payload = {
   272|    status: mcStatus,
   273|    ...extra,
   274|  };
   275|
   276|  const result = await mcFetch(`/api/tasks/${mapping.mcTaskId}`, {
   277|    method: 'PATCH',
   278|    body: JSON.stringify(payload),
   279|  });
   280|
   281|  return {
   282|    success: result.ok,
   283|    error: result.ok ? null : `MC update failed (${result.status}): ${JSON.stringify(result.data)}`,
   284|  };
   285|}
   286|
   287|/**
   288| * Get the MC ticket ref for a PLAN.md task ID.
   289| *
   290| * @param {string} planTaskId
   291| * @returns {string|null}
   292| */
   293|export function getTicketRef(planTaskId) {
   294|  const mapping = _taskMappings.get(planTaskId);
   295|  return mapping ? mapping.mcTicketRef : null;
   296|}
   297|
   298|// ─── Bulk Operations ───────────────────────────────────────────────────────────
   299|
   300|/**
   301| * Create MC tasks for all tasks in a parsed plan.
   302| *
   303| * @param {import('./parser.js').ParsedPlan} plan - Parsed plan object
   304| * @param {Object} [options]
   305| * @param {string} [options.projectId] - MC project ID
   306| * @param {boolean} [options.skipExisting=true] - Skip tasks already mapped
   307| * @returns {Promise<{created: number, skipped: number, failed: number, results: Object[]}>}
   308| */
   309|export async function syncPlanToMC(plan, options = {}) {
   310|  const results = [];
   311|  let created = 0, skipped = 0, failed = 0;
   312|
   313|  for (const task of plan.tasks) {
   314|    // Skip if already mapped
   315|    if (options.skipExisting !== false && _taskMappings.has(task.id)) {
   316|      skipped++;
   317|      results.push({ taskId: task.id, action: 'skipped', reason: 'already mapped' });
   318|      continue;
   319|    }
   320|
   321|    const res = await createMCTask(task, {
   322|      phase: plan.meta.phase,
   323|      projectId: options.projectId,
   324|    });
   325|
   326|    if (res.success) {
   327|      created++;
   328|      results.push({ taskId: task.id, action: 'created', ticketRef: res.ticketRef });
   329|    } else {
   330|      failed++;
   331|      results.push({ taskId: task.id, action: 'failed', error: res.error });
   332|    }
   333|  }
   334|
   335|  return { created, skipped, failed, results };
   336|}
   337|
   338|/**
   339| * Sync status updates from a STATE.md task status map to MC.
   340| *
   341| * @param {Object<string, string>} taskStatuses - Map of planTaskId → new status
   342| * @returns {Promise<{updated: number, failed: number, unmapped: number, results: Object[]}>}
   343| */
   344|export async function syncStatusToMC(taskStatuses) {
   345|  const results = [];
   346|  let updated = 0, failed = 0, unmapped = 0;
   347|
   348|  for (const [taskId, status] of Object.entries(taskStatuses)) {
   349|    if (!_taskMappings.has(taskId)) {
   350|      unmapped++;
   351|      results.push({ taskId, action: 'unmapped', status });
   352|      continue;
   353|    }
   354|
   355|    const res = await updateMCTaskStatus(taskId, status);
   356|    if (res.success) {
   357|      updated++;
   358|      results.push({ taskId, action: 'updated', status });
   359|    } else {
   360|      failed++;
   361|      results.push({ taskId, action: 'failed', error: res.error });
   362|    }
   363|  }
   364|
   365|  return { updated, failed, unmapped, results };
   366|}
   367|
   368|/**
   369| * Fetch all MC tasks for a project.
   370| *
   371| * @param {string} [projectId] - MC project ID, or omit for all tasks
   372| * @returns {Promise<{success: boolean, tasks: any[], error: string|null}>}
   373| */
   374|export async function fetchMCTasks(projectId) {
   375|  const path = projectId ? `/api/tasks?project_id=${projectId}` : '/api/tasks';
   376|  const result = await mcFetch(path);
   377|
   378|  if (result.ok) {
   379|    const tasks = Array.isArray(result.data) ? result.data : (result.data?.tasks || []);
   380|    return { success: true, tasks, error: null };
   381|  }
   382|
   383|  return {
   384|    success: false,
   385|    tasks: [],
   386|    error: result.error || `MC fetch failed (${result.status})`,
   387|  };
   388|}
   389|
   390|/**
   391| * Create or get an MC project for a GSD workspace.
   392| *
   393| * @param {string} name - Project name
   394| * @param {string} [description] - Project description
   395| * @returns {Promise<{success: boolean, projectId: string|null, error: string|null}>}
   396| */
   397|export async function ensureMCProject(name, description) {
   398|  const result = await mcFetch('/api/projects', {
   399|    method: 'POST',
   400|    body: JSON.stringify({ name, description: description || `GSD workspace: ${name}` }),
   401|  });
   402|
   403|  if (result.ok && result.data) {
   404|    return {
   405|      success: true,
   406|      projectId: result.data.id || result.data._id,
   407|      error: null,
   408|    };
   409|  }
   410|
