{"content": "     1|#!/usr/bin/env node
     2|/**
     3| * GSD Bridge — thin Node.js wrapper called by the Python daemon adapter.
     4| *
     5| * Usage:  node gsd_bridge.mjs <command> < input.json
     6| * Output: JSON to stdout
     7| *
     8| * Commands:
     9| *   health_check   — verify GSD package is importable
    10| *   poll_project    — check a project's state, return dispatchable tasks
    11| *   dispatch_wave   — dispatch a wave of tasks via GSD dispatcher
    12| *   update_status   — update a task's status in STATE.md
    13| *   list_projects   — list all discovered GSD projects
    14| */
    15|
    16|import { readFile } from 'node:fs/promises';
    17|import { join, resolve } from 'node:path';
    18|import { readdirSync, existsSync } from 'node:fs';
    19|
    20|const GSD_PACKAGE_DIR = process.env.GSD_PACKAGE_DIR || '/opt/data/gsd-lawyerinc';
    21|const GSD_PROJECTS_DIR = process.env.GSD_PROJECTS_DIR || '/opt/data/projects';
    22|
    23|/** Dynamic import of GSD library */
    24|let gsd = null;
    25|async function loadGSD() {
    26|  if (gsd) return gsd;
    27|  const indexPath = join(GSD_PACKAGE_DIR, 'src', 'index.js');
    28|  gsd = await import(indexPath);
    29|  return gsd;
    30|}
    31|
    32|/** Read JSON from stdin */
    33|async function readStdin() {
    34|  const chunks = [];
    35|  for await (const chunk of process.stdin) chunks.push(chunk);
    36|  const raw = Buffer.concat(chunks).toString().trim();
    37|  return raw ? JSON.parse(raw) : {};
    38|}
    39|
    40|/** Write JSON to stdout and exit */
    41|function respond(data) {
    42|  process.stdout.write(JSON.stringify(data) + '\n');
    43|  process.exit(0);
    44|}
    45|
    46|// ─── Commands ─────────────────────────────────────────────────────────────────
    47|
    48|async function healthCheck() {
    49|  const t0 = Date.now();
    50|  try {
    51|    await loadGSD();
    52|    respond({ ok: true, latency_ms: Date.now() - t0 });
    53|  } catch (err) {
    54|    respond({ ok: false, latency_ms: Date.now() - t0, error: err.message });
    55|  }
    56|}
    57|
    58|async function listProjects() {
    59|  const projects = [];
    60|  if (!existsSync(GSD_PROJECTS_DIR)) {
    61|    respond({ ok: true, projects: [] });
    62|    return;
    63|  }
    64|
    65|  for (const entry of readdirSync(GSD_PROJECTS_DIR, { withFileTypes: true })) {
    66|    if (!entry.isDirectory()) continue;
    67|    const stateFile = join(GSD_PROJECTS_DIR, entry.name, '.planning', 'STATE.md');
    68|    if (existsSync(stateFile)) {
    69|      projects.push({ name: entry.name, path: join(GSD_PROJECTS_DIR, entry.name) });
    70|    }
    71|  }
    72|  respond({ ok: true, projects });
    73|}
    74|
    75|async function pollProject(args) {
    76|  const { project, projectPath } = args;
    77|  const lib = await loadGSD();
    78|
    79|  const planningDir = join(projectPath || join(GSD_PROJECTS_DIR, project), '.planning');
    80|  const stateFile = join(planningDir, 'STATE.md');
    81|
    82|  // 1. Read state
    83|  let state;
    84|  try {
    85|    state = await lib.readState(stateFile);
    86|  } catch (err) {
    87|    respond({ ok: false, error: `Cannot read STATE.md: ${err.message}` });
    88|    return;
    89|  }
    90|
    91|  const lifecycle = state.lifecycle || state.meta?.lifecycle || '';
    92|
    93|  // Only process projects in EXECUTE lifecycle
    94|  if (lifecycle !== 'EXECUTE') {
    95|    respond({ ok: false, lifecycle, action: 'idle', reason: `Lifecycle is ${lifecycle}, not EXECUTE` });
    96|    return;
    97|  }
    98|
    99|  // 2. Find the current phase's PLAN.md
   100|  const currentPhase = state.phase || state.meta?.phase || '';
   101|  const currentWave = state.wave || state.meta?.wave || 1;
   102|
   103|  // Look for PLAN.md in phase dir or root .planning
   104|  const planPaths = [
   105|    join(planningDir, 'phases', currentPhase, 'PLAN.md'),
   106|    join(planningDir, 'PLAN.md'),
   107|  ];
   108|
   109|  let planFile = null;
   110|  for (const p of planPaths) {
   111|    if (existsSync(p)) { planFile = p; break; }
   112|  }
   113|
   114|  if (!planFile) {
   115|    respond({ ok: false, lifecycle, action: 'idle', reason: 'No PLAN.md found' });
   116|    return;
   117|  }
   118|
   119|  // 3. Parse the plan
   120|  let plan;
   121|  try {
   122|    plan = await lib.parsePlanFile(planFile);
   123|  } catch (err) {
   124|    respond({ ok: false, error: `Cannot parse PLAN.md: ${err.message}` });
   125|    return;
   126|  }
   127|
   128|  if (!plan.tasks || plan.tasks.length === 0) {
   129|    respond({ ok: false, lifecycle, action: 'idle', reason: 'No tasks in PLAN.md' });
   130|    return;
   131|  }
   132|
   133|  // 4. Check wave completion status
   134|  const waveComplete = lib.isWaveComplete(state, plan.tasks.filter(t => t.wave === currentWave));
   135|
   136|  // 5. Find tasks needing approval
   137|  const needsApproval = [];
   138|  for (const task of plan.tasks) {
   139|    const taskStatus = state.taskStatuses?.[task.id] || '';
   140|    if (task.approval === 'aaron' && taskStatus === 'reviewing') {
   141|      needsApproval.push(taskToJSON(task));
   142|    }
   143|  }
   144|
   145|  if (needsApproval.length > 0) {
   146|    respond({
   147|      ok: true,
   148|      lifecycle,
   149|      action: 'needs_approval',
   150|      wave: currentWave,
   151|      tasks: needsApproval,
   152|    });
   153|    return;
   154|  }
   155|
   156|  if (waveComplete) {
   157|    // Find next wave
   158|    const waves = lib.groupByWave(plan.tasks);
   159|    const waveNumbers = [...waves.keys()].sort((a, b) => a - b);
   160|    const currentIdx = waveNumbers.indexOf(currentWave);
   161|
   162|    if (currentIdx < waveNumbers.length - 1) {
   163|      // Next wave exists — dispatch it
   164|      const nextWave = waveNumbers[currentIdx + 1];
   165|      const nextWaveTasks = waves.get(nextWave) || [];
   166|
   167|      respond({
   168|        ok: true,
   169|        lifecycle,
   170|        action: 'dispatch_wave',
   171|        wave: nextWave,
   172|        tasks: nextWaveTasks.map(taskToJSON),
   173|      });
   174|      return;
   175|    } else {
   176|      // All waves complete — advance lifecycle
   177|      respond({
   178|        ok: true,
   179|        lifecycle,
   180|        action: 'advance_lifecycle',
   181|        next_lifecycle: 'VERIFY',
   182|      });
   183|      return;
   184|    }
   185|  }
   186|
   187|  // Wave not complete — check if we need to dispatch current wave
   188|  const currentWaveTasks = plan.tasks.filter(t => t.wave === currentWave);
   189|  const undispatched = currentWaveTasks.filter(t => {
   190|    const st = state.taskStatuses?.[t.id] || 'planned';
   191|    return st === 'planned';
   192|  });
   193|
   194|  if (undispatched.length > 0) {
   195|    respond({
   196|      ok: true,
   197|      lifecycle,
   198|      action: 'dispatch_wave',
   199|      wave: currentWave,
   200|      tasks: undispatched.map(taskToJSON),
   201|    });
   202|    return;
   203|  }
   204|
   205|  // Everything dispatched, waiting for completion
   206|  respond({
   207|    ok: true,
   208|    lifecycle,
   209|    action: 'idle',
   210|    wave: currentWave,
   211|    reason: `Wave ${currentWave} in progress — ${currentWaveTasks.length} tasks dispatched, waiting for completion`,
   212|  });
   213|}
   214|
   215|async function dispatchWave(args) {
   216|  const { project, projectPath, wave, tasks, dryRun } = args;
   217|  const lib = await loadGSD();
   218|
   219|  // Parse tasks and dispatch
   220|  const results = await lib.dispatchByWaves(tasks, {
   221|    dryRun: dryRun || false,
   222|    stopOnWaveFailure: true,
   223|  });
   224|
   225|  // Update STATE.md with dispatched statuses
   226|  const planningDir = join(projectPath || join(GSD_PROJECTS_DIR, project), '.planning');
   227|  const stateFile = join(planningDir, 'STATE.md');
   228|
   229|  try {
   230|    await lib.updateState(stateFile, (state) => {
   231|      for (const waveResult of results) {
   232|        for (const r of waveResult.results) {
   233|          if (r.success) {
   234|            lib.setTaskStatus(state, r.taskId, 'dispatched');
   235|          }
   236|        }
   237|      }
   238|      return state;
   239|    });
   240|  } catch (err) {
   241|    // Best effort — log but don't fail
   242|    process.stderr.write(`Warning: failed to update STATE.md: ${err.message}\n`);
   243|  }
   244|
   245|  respond({
   246|    ok: true,
   247|    waveResults: results,
   248|  });
   249|}
   250|
   251|async function updateStatus(args) {
   252|  const { project, taskId, status } = args;
   253|  const lib = await loadGSD();
   254|
   255|  const planningDir = join(GSD_PROJECTS_DIR, project, '.planning');
   256|  const stateFile = join(planningDir, 'STATE.md');
   257|
   258|  try {
   259|    await lib.updateState(stateFile, (state) => {
   260|      lib.setTaskStatus(state, taskId, status);
   261|      lib.recomputeMetrics(state);
   262|      return state;
   263|    });
   264|    respond({ ok: true });
   265|  } catch (err) {
   266|    respond({ ok: false, error: err.message });
   267|  }
   268|}
   269|
   270|/** Convert a parsed Task to a plain JSON-safe object */
   271|function taskToJSON(task) {
   272|  return {
   273|    id: task.id,
   274|    type: task.type || 'general',
   275|    assignee: task.assignee || '',
   276|    wave: task.wave || 1,
   277|    title: task.title || '',
   278|    description: task.description || '',
   279|    approval: task.approval || '',
   280|    verify: task.verify || '',
   281|    done: task.done || '',
   282|  };
   283|}
   284|
   285|// ─── Main ─────────────────────────────────────────────────────────────────────
   286|
   287|const command = process.argv[2];
   288|const args = await readStdin();
   289|
   290|switch (command) {
   291|  case 'health_check':
   292|    await healthCheck();
   293|    break;
   294|  case 'list_projects':
   295|    await listProjects();
   296|    break;
   297|  case 'poll_project':
   298|    await pollProject(args);
   299|    break;
   300|  case 'dispatch_wave':
   301|    await dispatchWave(args);
   302|    break;
   303|  case 'update_status':
   304|    await updateStatus(args);
   305|    break;
   306|  default:
   307|    respond({ ok: false, error: `Unknown command: ${command}` });
   308|}
